SELECT *
FROM t_car_cost_oil_card_initial_end
WHERE waybill_id = #{waybillId} AND oil_card_id = #{oilCardId}

SELECT ie.*,oil.oil_card_no
FROM t_car_cost_oil_card_initial_end ie left join t_oil_card oil on oil.oil_card_id = ie.oil_card_id
WHERE waybill_id = #{waybillId}

SELECT *
FROM t_car_cost_oil_card_initial_end
WHERE oil_card_initial_end_id > #{oilCardInitialEndId} AND oil_card_id = #{oilCardId}
